/*selectMessengerRoomsListCnt*/
SELECT COUNT(*)
FROM CHAT_ROOM r
JOIN CHAT_ROOM_MEMBER m
ON r.ROOM_ID = m.ROOM_ID
WHERE m.USER_ID = #{loginId}
AND r.ACTIVE_YN = 'Y'


    AND (
    r.TITLE LIKE '%' || #{searchValue} || '%'
    )

